+    /// Build Anthropic Messages API response format with custom stop_reason
+    fn buildAnthropicResponseWithStopReason(self: *Self, content: []const u8, completion_tokens: u32, prompt_len: usize, stop_reason: []const u8) ![]u8 {
+        // Escape content for JSON
+        var escaped: std.ArrayListUnmanaged(u8) = .{};
+        defer escaped.deinit(self.allocator);
