+    /// Stream new tokens for active streaming requests
+    fn streamTokensToClients(self: *Self) void {
+        self.queue_mutex.lock();
+        defer self.queue_mutex.unlock();
+
+        for (self.request_queue.items) |*req| {
+            // Only process streaming requests with assigned cells
+            if (!req.stream_mode) continue;
+            const cell_id = req.cell_id orelse continue;
+
+            const cell = &self.scheduler.cells[cell_id];
+
+            // Get current output buffer size
+            const current_len = cell.buffer.items.len;
+
+            // Check if we need to send SSE start
+            if (!req.sse_started) {
+                self.sendSSEHeaders(req.stream) catch continue;
+                self.sendAnthropicMessageStart(req.stream, req.id) catch continue;
+                self.sendAnthropicContentBlockStart(req.stream) catch continue;
+                req.sse_started = true;
+            }
+
+            // Check for stop sequences before streaming
+            if (req.stop_sequences) |stop_seqs| {
+                if (checkStopSequences(cell.buffer.items, stop_seqs)) |hit_seq| {
+                    req.hit_stop_sequence = hit_seq;
+                    // Mark cell as completed (will be handled in dispatchCompletedResponses)
+                    cell.state = .completed;
+                    continue;
+                }
+            }
+
+            // Stream any new bytes
+            if (current_len > req.bytes_sent) {
+                const new_text = cell.buffer.items[req.bytes_sent..current_len];
+                self.sendAnthropicContentBlockDelta(req.stream, new_text) catch continue;
+                req.bytes_sent = current_len;
+            }
+        }
+    }
+
+    /// Handle streaming completion (send final events and cleanup)
+    fn handleStreamingCompletion(self: *Self, req: *PendingRequest, cell: *Cell) void {
+        // Send any remaining text (up to stop sequence if hit)
+        var end_pos = cell.buffer.items.len;
+        if (req.hit_stop_sequence) |stop_seq| {
+            // Find where the stop sequence starts and truncate
+            if (std.mem.lastIndexOf(u8, cell.buffer.items, stop_seq)) |idx| {
+                end_pos = idx;
+            }
+        }
+
+        if (end_pos > req.bytes_sent) {
+            const new_text = cell.buffer.items[req.bytes_sent..end_pos];
+            self.sendAnthropicContentBlockDelta(req.stream, new_text) catch {};
+        }
+
+        // Send completion events
+        self.sendAnthropicContentBlockStop(req.stream) catch {};
+
+        // Use stop_sequence reason if we hit one
+        if (req.hit_stop_sequence != null) {
+            self.sendAnthropicMessageDeltaWithStopSequence(req.stream, cell.generated_count) catch {};
+        } else {
+            self.sendAnthropicMessageDelta(req.stream, cell.generated_count) catch {};
+        }
+        self.sendAnthropicMessageStop(req.stream) catch {};
+    }
