+
+/// Extract text content from Anthropic message content field
+/// Handles both:
+/// - Simple string: "content": "Hello"
+/// - Content blocks: "content": [{"type": "text", "text": "Hello"}]
+fn extractContentText(allocator: std.mem.Allocator, content_value: std.json.Value) ![]u8 {
+    switch (content_value) {
+        .string => |s| {
+            return try allocator.dupe(u8, s);
+        },
+        .array => |arr| {
+            // Concatenate all text blocks
+            var text_builder: std.ArrayListUnmanaged(u8) = .{};
+            errdefer text_builder.deinit(allocator);
+
+            for (arr.items) |block| {
+                if (block != .object) continue;
+                const obj = block.object;
+
+                // Check if this is a text block
+                const block_type = obj.get("type") orelse continue;
+                if (block_type != .string) continue;
+                if (!std.mem.eql(u8, block_type.string, "text")) continue;
+
+                // Get the text field
+                const text_value = obj.get("text") orelse continue;
+                if (text_value != .string) continue;
+
+                try text_builder.appendSlice(allocator, text_value.string);
+            }
+
+            return try allocator.dupe(u8, text_builder.items);
+        },
+        else => {
+            return try allocator.dupe(u8, "");
+        },
+    }
+}
