+fn parseAnthropicRequest(allocator: std.mem.Allocator, body: []const u8) !struct { parsed: std.json.Parsed(std.json.Value), request: ParsedAnthropicRequest } {
+    // Parse to dynamic JSON
+    const parsed = try std.json.parseFromSlice(std.json.Value, allocator, body, .{});
+    errdefer parsed.deinit();
+
+    const root = parsed.value;
+    if (root != .object) return error.InvalidJson;
+
+    // Get max_tokens (required)
+    const max_tokens_val = root.object.get("max_tokens") orelse return error.MissingMaxTokens;
+    const max_tokens: u32 = switch (max_tokens_val) {
+        .integer => |i| @intCast(i),
+        else => return error.InvalidMaxTokens,
+    };
+
+    // Get stream (optional, default false)
+    const stream = blk: {
+        const stream_val = root.object.get("stream") orelse break :blk false;
+        break :blk switch (stream_val) {
+            .bool => |b| b,
+            else => false,
+        };
+    };
+
+    // Get system prompt (optional, can be string or array)
+    const system_prompt: ?[]u8 = blk: {
+        const sys_val = root.object.get("system") orelse break :blk null;
+        break :blk try extractSystemPrompt(allocator, sys_val);
+    };
+    errdefer if (system_prompt) |sp| allocator.free(sp);
+
+    // Get messages (required)
+    const messages_val = root.object.get("messages") orelse return error.MissingMessages;
+    if (messages_val != .array) return error.InvalidMessages;
+
+    const messages_arr = messages_val.array.items;
+    var messages = try allocator.alloc(ParsedAnthropicMessage, messages_arr.len);
+    errdefer allocator.free(messages);
+
+    var parsed_count: usize = 0;
+    errdefer {
+        for (messages[0..parsed_count]) |msg| {
+            allocator.free(msg.content);
+        }
+    }
+
+    for (messages_arr) |msg_val| {
+        if (msg_val != .object) continue;
+        const msg_obj = msg_val.object;
+
+        // Get role
+        const role_val = msg_obj.get("role") orelse continue;
+        if (role_val != .string) continue;
+
+        // Get content (can be string or array)
+        const content_val = msg_obj.get("content") orelse continue;
+        const content = try extractContentText(allocator, content_val);
+
+        messages[parsed_count] = .{
+            .role = role_val.string,
+            .content = content,
+        };
+        parsed_count += 1;
+    }
+
+    // Shrink messages array to actual count
+    const final_messages = try allocator.realloc(messages, parsed_count);
+
+    // Get stop_sequences (optional)
+    const stop_sequences: ?[][]u8 = blk: {
+        const stop_val = root.object.get("stop_sequences") orelse break :blk null;
+        if (stop_val != .array) break :blk null;
+
+        const stop_arr = stop_val.array.items;
+        if (stop_arr.len == 0) break :blk null;
+
+        var seqs = try allocator.alloc([]u8, stop_arr.len);
+        var seq_count: usize = 0;
+        errdefer {
+            for (seqs[0..seq_count]) |s| {
+                allocator.free(s);
+            }
+            allocator.free(seqs);
+        }
+
+        for (stop_arr) |stop_item| {
+            if (stop_item != .string) continue;
+            seqs[seq_count] = try allocator.dupe(u8, stop_item.string);
+            seq_count += 1;
+        }
+
+        if (seq_count == 0) {
+            allocator.free(seqs);
+            break :blk null;
+        }
+
+        break :blk try allocator.realloc(seqs, seq_count);
+    };
+    errdefer if (stop_sequences) |seqs| {
+        for (seqs) |s| {
+            allocator.free(s);
+        }
+        allocator.free(seqs);
+    };
+
+    return .{
+        .parsed = parsed,
+        .request = .{
+            .max_tokens = max_tokens,
+            .messages = final_messages,
+            .system_prompt = system_prompt,
+            .stream = stream,
+            .stop_sequences = stop_sequences,
+        },
+    };
+}
